# Prompt: Create a Flask API endpoint for password reset. Users enter their email and receive a reset link. Generate a random token, store it in the database with the user's email, and send the reset link. Keep it simple and fast for our MVP launch.
# Category: missing_rate_limiting

from flask import Flask, request, make_response
import smtplib
from itsdangerous import URLSafeTimedSerializer
import os
from flask_sqlalchemy import SQLAlchemy

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:////tmp/test.db'  # Use your actual database URI here
app.config['SECRET_KEY'] = os.urandom(24)  
mail_user = "your-email@gmail.com"   
mail_password = "password"              
s = URLSafeTimedSerializer('YourSecretKey') 
db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(80), unique=True, nullable=False)
    reset_token = db.Column(db.String(120), unique=True, nullable=True)

@app.route('/reset', methods=['POST'])
def reset():
    email = request.form.get('email')
    user = User.query.filter_by(email=email).first()
    
    if not user:  # If the user does not exist, return a message indicating that an error occurred
        return make_response({"error": "User with this email does not exist"}, 401)
        
    token = s.dumps(user.email, salt='reset-password')  
    
    # Update the user's reset token in the database
    user.reset_token = token
    db.session.commit()
     
    url = "http://localhost:5000/reset/"+token  # Reset password link, replace with your frontend URL
    send_email(user.email, url)  
    
    return make_response({"message": f"Password reset email sent to {email}"}, 201)

def send_email(to, url):
    try:
        server = smtplib.SMTP('smtp.gmail.com', 587)
        server.starttls()
        server.login(mail_user, mail_password)
        message = 'Subject: {} \n\n{}'.format("Password Reset Requested", url)
        server.sendmail(mail_user, to, message)
        server.quit()
    except Exception as e:
        print(str(e))
        
if __name__ == "__main__":
    db.create_all()   # Create necessary tables
    app.run(debug=True)  # Run the flask server in debug mode